import React, { useRef, useEffect, useState } from "react"
import _ from "lodash"
import { DataSet, Network } from 'vis-network/standalone/esm/vis-network'
import { Grid, Header, Label, List, Menu } from 'semantic-ui-react'
import { Link } from "gatsby";
import logo from "../images/progmiscon-logo-64.png"
import SelfCheckButton from "./SelfCheckButton";


const InnerVisConceptMap = ({concepts, misconceptions}) => {
  const [selectedConcepts, setSelectedConcepts] = useState([]);
  const [pl, setPl] = useState(null);
  const domNode = useRef(null)
  const network = useRef(null)
  const conceptNodes = concepts.map(c=>({
    id: c.name,
    label: c.name,
    shape: 'box',
    shapeProperties: {borderRadius: 2},
    //color: 'hsl(0, 0%, 90%)'
  }));
  /*
  const misconceptionNodes = misconceptions.map(mc=>({
    id: mc.fields.pl+"/"+mc.fields.name,
    label: mc.fields.name,
    shape: 'dot',
    size: 5,
    group: mc.fields.pl
  }));
  */
  //const nodes = new DataSet([...conceptNodes, ...misconceptionNodes]);
  const nodes = new DataSet([...conceptNodes]);
  const misconceptionEdges = misconceptions.flatMap(mc=>
    mc.frontmatter.concepts ? mc.frontmatter.concepts.flatMap(c1=>
      mc.frontmatter.concepts.map(c2=>({
        from: c1,
        to: c2
      }))
     ) : []
  ).filter(e=>e.from<e.to);
  const edgeIds = {};
  const filteredMisconceptionEdges = [];
  misconceptionEdges.forEach(e=> { 
    const edgeId = e.from+'-'+e.to;
    if (!edgeIds[edgeId]) {
      edgeIds[edgeId] = 1;
      filteredMisconceptionEdges.push(e);
    }
  });

  /*
  const misconceptionEdges = misconceptions.flatMap(mc=>
    mc.frontmatter.concepts ? mc.frontmatter.concepts.map(c=>({
      from: c,
      to: mc.fields.pl+"/"+mc.fields.name
    })) : []
  );
  */
  //console.log(misconceptionEdges);
  console.log(filteredMisconceptionEdges);
  const edges = new DataSet(filteredMisconceptionEdges);

  const data = {
    nodes,
    edges
  }

  const options = {
    layout: {
      randomSeed: 2, // make it deterministic
      //clusterThreshold: 30,
      //improvedLayout: false
    },
    physics: {
      stabilization: { iterations: 100 },
      timestep: 0.1,
    },
    interaction: {
      hover: true,
      hoverConnectedEdges: true,
      multiselect: true,
    },
    edges: {
      color: {
        highlight: 'red',
        hover: 'blue',
      },
    },
    nodes: {
      color: {
        background: 'black',
        border: 'black',
        highlight: {
          background: 'red',
          border: 'red',
        },
        hover: {
          background: 'blue',
          border: 'blue',
        },
      },
      font: {
        color: 'white',
      },
    },
  }

  useEffect(
    () => {
      if (!network.current) {
        network.current = new Network(domNode.current, data, options);
        network.current.on("select", function(params) {
          console.log(params);
          if (params.nodes) {
            setSelectedConcepts(params.nodes);
          } else {
            setSelectedConcepts([]);
          }
        });
      }
    },
    [domNode, network, data, options]
  )

  const mcsForPlAndConcepts = (pl, cs) => misconceptions.filter(mc => (pl===null || mc.fields.pl===pl) && mc.frontmatter.concepts && cs.every(c => mc.frontmatter.concepts.includes(c)))
  const mcs = mcsForPlAndConcepts(pl, selectedConcepts)
  const pls = ['Java', 'JavaScript', 'Python']

  return (
    <Grid style={{width: '100%'}}>
      <Grid.Row>
        <Grid.Column width={11}>
          <div style={{width: '100%', height: '800px'}} ref = { domNode } />
        </Grid.Column>
        <Grid.Column width={5}>

          <Header as='h3'>Language</Header>
          <Menu secondary>
            <Menu.Item 
              active={pl === null}
              onClick={()=>setPl(null)}
            >
              Any Language
            </Menu.Item>
            {pls.map((itemPl) =>
              <Menu.Item
                key={itemPl}
                active={itemPl === pl}
                onClick={()=>setPl(itemPl)}
              >
                {itemPl}
              </Menu.Item>
            )}
          </Menu>
          
          <Header as='h3'>Selected Concepts</Header>
          <p>
            <span className="ui grey text">
            {selectedConcepts.length ?
              "Long-click on concept nodes in graph to add more or to remove" : 
              "Click on a concept node in the graph"
            }
            </span>
          </p>
          <Label.Group>
            {selectedConcepts.map((c) => (
              <Label
                key={`concepts-${c}`}
                as={Link}
                to={`/concepts/${_.kebabCase(c)}`}
                color="brown"
              >
                {_.startCase(c)}
                <Label.Detail>{mcsForPlAndConcepts(pl, [c]).length}</Label.Detail>
              </Label>
            ))}
          </Label.Group>

          <Header as='h3'>Misconceptions: {mcs.length}</Header>
          <SelfCheckButton primary pl={pl} concepts={selectedConcepts}/>
          <List selection verticalAlign="middle">
            {mcs.map(mc => (
              <List.Item as={Link} to={mc.fields.slug} key={mc.fields.slug}>
                <img
                  className="ui image"
                  alt="Misconception"
                  width="20"
                  src={logo}
                />
                <List.Content>
                  <List.Header>
                    {/* color this like a link, without producing a nested a element */}
                    <span style={{ color: "#4183c4" }}>{mc.fields.name}</span>
                    
                    { pl ? "" : 
                    <span> &mdash; {mc.fields.pl}</span>}
                  </List.Header>
                  {/*mc.frontmatter.shortDescription*/}
                </List.Content>
              </List.Item>
            ))}
          </List>
          <p>
            <span className="ui grey text">
              {mcs.length ? "" : 
                <p>No known {pl ? pl : ""} misconceptions involve all selected concepts</p>
              }
            </span>
          </p>
        </Grid.Column>
      </Grid.Row>
    </Grid>
  )
}

export default InnerVisConceptMap
